def _normalize_cell(v: Any) -> Any:
    if v is None:
        return None
    if isinstance(v, datetime.datetime):
        return v.replace(tzinfo=None).date().isoformat()
    if isinstance(v, datetime.date):
        return v.isoformat()
    if isinstance(v, bytes):
        return v.decode("utf-8")
    if isinstance(v, float):
        return v
    if isinstance(v, int):
        return float(v)
    return str(v)


def _materialize_ydb_row(row: Any) -> tuple[Any, ...]:
    if hasattr(row, "__len__") and not isinstance(row, (str, bytes)):
        return tuple(_normalize_cell(row[i]) for i in range(len(row)))
    raise TypeError(f"unexpected row type: {type(row)}")


def _row_almost_equal(a: Sequence[Any], b: Sequence[Any]) -> bool:
    if len(a) != len(b):
        return False
    for x, y in zip(a, b):
        if x == y:
            continue
        try:
            if math.isclose(float(x), float(y), rel_tol=1e-4, abs_tol=1e-6):
                continue
        except (TypeError, ValueError):
            pass
        if str(x) == str(y):
            continue
        return False
    return True


def _multiset_equal(expected: list[list[Any]], actual_rows: Sequence[Any]) -> None:
    act = [_materialize_ydb_row(r) for r in actual_rows]
    exp = [tuple(_normalize_cell(c) for c in row) for row in expected]
    if len(exp) != len(act):
        raise AssertionError(
            f"row count: expected {len(exp)}, got {len(act)}\n"
            f"  expected: {exp[:5]}\n"
            f"  actual:   {act[:5]}"
        )
    used = [False] * len(act)
    for er in exp:
        found = False
        for j, ar in enumerate(act):
            if used[j]:
                continue
            if _row_almost_equal(er, ar):
                used[j] = True
                found = True
                break
        if not found:
            raise AssertionError(
                f"no matching row for expected {er!r}\n  actual: {act!r}"
            )


def assert_matches_postgres(
    result_sets: Sequence[Any],
    expected: list[list[Any]] | None,
    *,
    query_label: str,
) -> None:
    """Assert that YDB result matches the PostgreSQL oracle."""
    if expected is None:
        raise AssertionError(f"{query_label}: expected is None (xfail not applied?)")
    if result_sets is None or len(result_sets) == 0:
        raise AssertionError(f"{query_label}: empty result from YDB")
    rows = result_sets[0].rows
    if len(expected) == 0:
        assert len(rows) == 0, (
            f"{query_label}: expected 0 rows, got {len(rows)}: {list(rows)[:3]}"
        )
        return
    _multiset_equal(expected, rows)
